    },
    {
      "expectation_id": "说明每次赔付金额比例",
      "status": "fulfilled",
      "reasoning": "回答明确给出“每次赔付金额通常为基本保险金额的20%至30%”，与参考答案中的比例范围相符。"
    },
    {
      "expectation_id": "提及次数上限和间隔期",
      "status": "fulfilled",
      "reasoning": "回答提到“可能有次数上限（如3次或5次）和间隔期要求”，涵盖了次数上限和间隔期这两个核心条件，尽管未列出具体间隔天数，但已满足提及要求。"
    },
    {
      "expectation_id": "覆盖轻症赔付的其他重要限制",
      "status": "not_fulfilled",
      "reasoning": "回答完全未提及轻症分组限制、累计赔付上限、或重疾保额可能因轻症赔付而减少等重要条款，没有覆盖这些关键限制信息。"
    },
    {
      "expectation_id": "提供合同查阅的具体指导",
      "status": "not_fulfilled",
      "reasoning": "回答仅宽泛地建议“查阅您的保险合同条款”，未指定具体章节（如“保险责任”及“轻症疾病保险金”）或建议咨询客服，缺乏具体指导。"
    },
    {
      "expectation_id": "信息忠实于参考答案且无矛盾",
      "status": "fulfilled",
      "reasoning": "回答中的所有陈述在参考答案中均可找到对应依据，没有引入事实错误或与参考矛盾的内容。"
    }
  ],
  "overall_fulfillment": {
    "status": "not_fulfilled",
    "reasoning": "虽然回答了核心的赔付次数和比例，且信息准确，但由于遗漏了轻症分组限制、累计赔付上限、重疾保额变动等关键限制条件，以及缺乏具体的合同查阅指导，导致回答的完整性和实用性不足，不符合golden answer场景下对完整性和关键点覆盖的期望。"
  },
  "expected": {},
  "missing": [
    {
      "point": "轻症责任可能设有分组限制，同一组别的轻症只能赔付一次"
    },
    {
      "point": "轻症赔付存在累计赔付上限"
    },
    {
      "point": "部分产品轻症赔付后重疾保额会相应减少"
    },
    {
      "point": "建议查阅合同的“保险责任”及“轻症疾病保险金”章节，或直接咨询保险公司客服"
    }
  ],
  "wrong": [],
  "extra": [],
  "evidence": [],
  "reasoning_summary": "本案例为qa_gold_answer场景，采用golden answer作为评价基准。用户提问关于轻症多次赔付及每次赔付金额。实际回答虽然正确回答了基本次数和比例问题，且提到了次数上限和间隔期，但忽略了参考答案中明确指出的分组限制、累计赔付上限、重疾保额可能减少等重要条款，也未提供合同查阅的具体章节或客服建议，导致回答的完整性不足，可能使用户对轻症赔付规则产生不全面的理解。因此多个关键期望未满足，整体判定为not_fulfilled。"
}

